/// Binary search the (id-sorted) table.
pub fn fieldsFor(id: u32) ?[]const Field {
    var lo: usize = 0;
    var hi: usize = ctors.len;
    while (lo < hi) {
        const mid = lo + (hi - lo) / 2;
        const c = ctors[mid];
        if (c.id == id) return c.fields;
        if (c.id < id) lo = mid + 1 else hi = mid;
    }
    return null;
}
